1	const isNeighbor = (cell: number[], other: number[]): boolean =>
2	  !(other[0] === cell[0] && other[1] === cell[1]) &&
3	  Math.abs(other[0] - cell[0]) <= 1 &&
4	  Math.abs(other[1] - cell[1]) <= 1;
5	
6	const countNeighbors = (cell: number[], liveCells: number[][]): number =>
7	  liveCells.filter((other) => isNeighbor(cell, other)).length;
8	
9	export function nextGeneration(liveCells: number[][]): number[][] {
10	  return liveCells.filter((cell) => {
11	    const neighborCount = countNeighbors(cell, liveCells);
12	    return neighborCount === 2 || neighborCount === 3;
13	  });
14	}
